/**
 * MercadoPago Integration Script for mcashop.mx
 *
 * Description: Provides functions for handling MercadoPago payment processes
 * within mcashop.mx, including initialization, validation, and
 * transaction handling.
 *
 * Property of: mcashop.mx
 * Developed by: @gabinosarmiento
 * Last Updated: November 14, 2024
 * Version: 1.1
 */
var mercadopago_script = document.createElement("script");
mercadopago_script.src = "https://sdk.mercadopago.com/js/v2", document.head.appendChild(mercadopago_script), mercadopago_script.onload = function() {
    let e = new MercadoPago(MERCADOPAGO.KEY, {
            locale: "es-MX"
        }),
        a = e.bricks(),
        t = async () => {
            window.paymentBrickController && (window.paymentBrickController.unmount(), window.paymentBrickController = null);
            let e = {
                initialization: {
                    amount: MERCADOPAGO.TOTAL,
                    preferenceId: MERCADOPAGO.PREFERENCE_ID
                },
                customization: {
                    visual: {
                        style: {
                            customVariables: {
                                formPadding: "10px",
                                borderRadiusMedium: "30px"
                            }
                        }
                    },
                    paymentMethods: {
                        atm: "all",
                        ticket: "all",
                        creditCard: "all",
                        debitCard: "all",
                        bankTransfer: "all",
                        wallet_purchase: "all",
                        maxInstallments: 12
                    }
                },
                callbacks: {
                    onReady() {},
                    onSubmit: ({
                        selectedPaymentMethod: e,
                        formData: a
                    }) => new Promise((e, t) => {
                        fetch(MERCADOPAGO.PAY_ORDER, {
                            method: "POST",
                            headers: {
                                "Content-Type": "application/json",
                                "X-CSRF-TOKEN": MERCADOPAGO.CSRF
                            },
                            body: JSON.stringify(a)
                        }).then(e => e.ok ? e.json() : e.json().then(e => {
                            throw Error(e.message)
                        })).then(a => {
                            document.body.notification({
                                body: a.message,
                                type: "success"
                            }), setTimeout(() => {
                                window.location.href = MERCADOPAGO.REDIRECT_URL
                            }, 5e3), e()
                        }).catch(e => {
                            document.body.notification({
                                body: e.message,
                                type: "danger"
                            }), t()
                        })
                    }),
                    onError(e) {
                        console.error("Resultado error: ", e)
                    }
                }
            };
            window.paymentBrickController = await a.create("payment", "payment_container", e)
        };
    t()
};